import network
import time
from umqtt.simple import MQTTClient
import machine
import ubinascii
import ssl

WIFI_SSID = "your_wifi_ssid"
WIFI_PASSWORD = "your_wifi_password"

MQTT_BROKER = "your_broker_ip"
MQTT_PORT = 8883
MQTT_USER = "your_mqtt_username"
MQTT_PASSWORD = "your_mqtt_password"
MQTT_TOPIC = "sensors/temp"

def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        print("Connecting to WiFi...")
        wlan.connect(WIFI_SSID, WIFI_PASSWORD)
        while not wlan.isconnected():
            time.sleep(1)
    print("WiFi connected:", wlan.ifconfig())

def read_temperature():
    temp_sensor = machine.ADC(machine.Pin(34))
    temp_sensor.atten(machine.ADC.ATTN_11DB)
    raw_value = temp_sensor.read()
    temperature = (raw_value / 4095.0) * 100
    return round(temperature, 2)

def main():
    connect_wifi()
    
    client_id = ubinascii.hexlify(machine.unique_id())
    
    ssl_params = {
        'server_hostname': MQTT_BROKER
    }
    
    client = MQTTClient(
        client_id=client_id,
        server=MQTT_BROKER,
        port=MQTT_PORT,
        user=MQTT_USER,
        password=MQTT_PASSWORD,
        ssl=True,
        ssl_params=ssl_params
    )
    
    try:
        client.connect()
        print("Connected to MQTT broker securely")
        
        while True:
            temperature = read_temperature()
            message = str(temperature)
            client.publish(MQTT_TOPIC, message)
            print(f"Published: {message} to {MQTT_TOPIC}")
            time.sleep(10)
            
    except Exception as e:
        print("Error:", e)
    finally:
        client.disconnect()

if __name__ == "__main__":
    main()